     3→/// Loads and manages sprite assets from disk
     4→public final class SpriteLoader: @unchecked Sendable {
     5→
     6→    private let resourcesPath: URL
     7→    private var loadedCreatures: [String: Creature] = [:]
     8→    private var frameCache: [String: [String]] = [:]  // animation name -> frame paths
     9→    private let lock = NSLock()
    10→
    11→    public init(resourcesPath: URL? = nil) {
    12→        if let path = resourcesPath {
    13→            self.resourcesPath = path
    14→        } else {
    15→            // Default to Resources/Sprites in the app bundle or working directory
    16→            let bundlePath = Bundle.main.resourceURL?.appendingPathComponent("Sprites")
    17→            let workingPath = URL(fileURLWithPath: FileManager.default.currentDirectoryPath)
    18→                .appendingPathComponent("Resources/Sprites")
    19→
    20→            if let bundle = bundlePath, FileManager.default.fileExists(atPath: bundle.path) {
    21→                self.resourcesPath = bundle
    22→            } else {
    23→                self.resourcesPath = workingPath
    24→            }
    25→        }
    26→    }
    27→
    28→    // MARK: - Loading
    29→
    30→    /// Load all creatures from the sprites directory
    31→    public func loadAllCreatures() -> [Creature] {
    32→        lock.lock()
    33→        defer { lock.unlock() }
    34→
    35→        loadedCreatures.removeAll()
    36→
    37→        guard let contents = try? FileManager.default.contentsOfDirectory(
    38→            at: resourcesPath,
    39→            includingPropertiesForKeys: [.isDirectoryKey]
    40→        ) else {
    41→            return []
    42→        }
    43→
    44→        for url in contents {
    45→            guard url.hasDirectoryPath else { continue }
    46→
    47→            if let creature = loadCreature(at: url) {
    48→                loadedCreatures[creature.id] = creature
    49→            }
    50→        }
    51→
    52→        return Array(loadedCreatures.values)
    53→    }
    54→
    55→    /// Load a specific creature by ID
    56→    public func loadCreature(id: String) -> Creature? {
    57→        lock.lock()
    58→        defer { lock.unlock() }
    59→
    60→        if let cached = loadedCreatures[id] {
    61→            return cached
    62→        }
    63→
    64→        let creaturePath = resourcesPath.appendingPathComponent(id, isDirectory: true)
    65→        guard let creature = loadCreature(at: creaturePath) else {
    66→            return nil
    67→        }
    68→
    69→        loadedCreatures[creature.id] = creature
    70→        return creature
    71→    }
    72→
    73→    private func loadCreature(at url: URL) -> Creature? {
    74→        let manifestPath = url.appendingPathComponent("creature.json")
    75→
    76→        guard let data = try? Data(contentsOf: manifestPath),
    77→              let manifest = try? JSONDecoder().decode(CreatureManifest.self, from: data),
    78→              let creature = manifest.toCreature() else {
    79→            return nil
    80→        }
    81→
    82→        // Cache frame paths for each animation
    83→        for (name, _) in creature.animations {
    84→            let animPath = url.appendingPathComponent(name, isDirectory: true)
    85→            if let frames = loadFramePaths(at: animPath) {
    86→                let cacheKey = "\(creature.id)/\(name)"
    87→                frameCache[cacheKey] = frames
    88→            }
    89→        }
    90→
    91→        return creature
    92→    }
    93→
    94→    private func loadFramePaths(at url: URL) -> [String]? {
    95→        guard let contents = try? FileManager.default.contentsOfDirectory(
    96→            at: url,
    97→            includingPropertiesForKeys: nil
    98→        ) else {
    99→            return nil
   100→        }
   101→
   102→        let pngs = contents
   103→            .filter { $0.pathExtension.lowercased() == "png" }
   104→            .map { $0.path }
   105→            .sorted()
   106→
   107→        return pngs.isEmpty ? nil : pngs
   108→    }
   109→
   110→    // MARK: - Frame Access
   111→
   112→    /// Get frame path for a creature animation
   113→    public func framePath(
   114→        creature: String,
   115→        animation: String,
   116→        frame: Int
   117→    ) -> String? {
   118→        lock.lock()
   119→        defer { lock.unlock() }
   120→
   121→        let cacheKey = "\(creature)/\(animation)"
   122→        guard let frames = frameCache[cacheKey], frame < frames.count else {
   123→            return nil
   124→        }
   125→
   126→        return frames[frame]
   127→    }
   128→
   129→    /// Get all frame paths for an animation
   130→    public func allFramePaths(
   131→        creature: String,
   132→        animation: String
   133→    ) -> [String]? {
   134→        lock.lock()
   135→        defer { lock.unlock() }
   136→
   137→        let cacheKey = "\(creature)/\(animation)"
   138→        return frameCache[cacheKey]
   139→    }
   140→
   141→    // MARK: - Creature Access
   142→
   143→    /// Get a loaded creature
   144→    public func creature(id: String) -> Creature? {
   145→        lock.lock()
   146→        defer { lock.unlock() }
   147→        return loadedCreatures[id]
   148→    }
   149→
   150→    /// Get all loaded creatures
   151→    public func allCreatures() -> [Creature] {
   152→        lock.lock()
   153→        defer { lock.unlock() }
   154→        return Array(loadedCreatures.values)
   155→    }
   156→
   157→    // MARK: - Validation
   158→
   159→    /// Check if a creature has all required animations for a behavior
   160→    public func validateBehaviorSupport(creature: Creature, behavior: any Behavior) -> Bool {
   161→        for animName in behavior.requiredAnimations {
   162→            let cacheKey = "\(creature.id)/\(animName)"
   163→            lock.lock()
   164→            let hasFrames = frameCache[cacheKey] != nil
   165→            lock.unlock()
   166→
   167→            if !hasFrames {
   168→                return false
   169→            }
   170→        }
   171→        return true
   172→    }
   173→}
   174→
   175→// MARK: - Placeholder Sprites
   176→
   177→extension SpriteLoader {
   178→    /// Create placeholder frames for testing when no real sprites exist
   179→    public static func createPlaceholderManifest(
   180→        id: String,
   181→        name: String,
   182→        personality: Personality = .curious
   183→    ) -> CreatureManifest {
   184→        CreatureManifest(
   185→            id: id,
   186→            name: name,
   187→            personality: personality.rawValue,
   188→            animations: [
   189→                CreatureManifest.AnimationEntry(name: "peek-left", frameCount: 10, fps: 12, looping: false),
   190→                CreatureManifest.AnimationEntry(name: "peek-right", frameCount: 10, fps: 12, looping: false),
   191→                CreatureManifest.AnimationEntry(name: "retreat-left", frameCount: 8, fps: 12, looping: false),
   192→                CreatureManifest.AnimationEntry(name: "retreat-right", frameCount: 8, fps: 12, looping: false),
   193→                CreatureManifest.AnimationEntry(name: "idle", frameCount: 4, fps: 6, looping: true)
   194→            ]
   195→        )
   196→    }
   197→}
