     4→/// Thread-safe image cache for sprite frames
     5→final class ImageCache: @unchecked Sendable {
     6→    static let shared = ImageCache()
     7→
     8→    private var cache: [String: NSImage] = [:]
     9→    private let lock = NSLock()
    10→    private let maxCacheSize = 500  // Max images to keep
    11→
    12→    private init() {}
    13→
    14→    /// Get cached image or load from path
    15→    func image(for path: String) -> NSImage? {
    16→        lock.lock()
    17→        if let cached = cache[path] {
    18→            lock.unlock()
    19→            return cached
    20→        }
    21→        lock.unlock()
    22→
    23→        // Load from disk
    24→        guard let image = NSImage(contentsOfFile: path) else {
    25→            return nil
    26→        }
    27→
    28→        lock.lock()
    29→        // Evict if needed
    30→        if cache.count >= maxCacheSize {
    31→            // Simple eviction: remove half
    32→            let keysToRemove = Array(cache.keys.prefix(maxCacheSize / 2))
    33→            for key in keysToRemove {
    34→                cache.removeValue(forKey: key)
    35→            }
    36→        }
    37→        cache[path] = image
    38→        lock.unlock()
    39→
    40→        return image
    41→    }
    42→
    43→    /// Preload images for faster playback
    44→    func preload(paths: [String]) {
    45→        for path in paths {
    46→            _ = image(for: path)
    47→        }
    48→    }
    49→
    50→    /// Clear all cached images
    51→    func clear() {
    52→        lock.lock()
    53→        cache.removeAll()
    54→        lock.unlock()
    55→    }
    56→
    57→    /// Preload all frames for a creature's animations
    58→    func preloadCreature(id: String, animations: [String], spriteLoader: SpriteLoader) {
    59→        for animName in animations {
    60→            if let frames = spriteLoader.allFramePaths(creature: id, animation: animName) {
    61→                preload(paths: frames)
    62→            }
    63→        }
    64→    }
    65→}
